import subprocess, json

result = subprocess.run(
    ["ssh-agent", "bash", "-c",
     "ssh-add /root/.ssh/id_rsa 2>/dev/null; ssh -o StrictHostKeyChecking=no -o ConnectTimeout=10 agentzero 'docker service inspect traefik_traefik 2>/dev/null'",
    ],
    capture_output=True, text=True, timeout=20
)
if result.returncode == 0 and result.stdout:
    try:
        data = json.loads(result.stdout)
        spec = data[0]["Spec"]
        networks = spec.get("Networks", [])
        print("Networks:", json.dumps(networks, indent=2))
        # Check for labels
        container = spec.get("TaskTemplate", {}).get("ContainerSpec", {})
        labels = container.get("Labels", {})
        print("Labels found:", len(labels))
        # Check for mounts to see config dirs
        mounts = container.get("Mounts", [])
        for m in mounts:
            if "traefik" in str(m).lower() or "dynamic" in str(m).lower():
                print(f"Mount: {m.get('Source')} -> {m.get('Target')}")
    except Exception as e:
        print(f"Parse error: {e}")
        print(result.stdout[:2000])
else:
    print(f"Error: {result.stderr[:500]}")
"}

